public boolean checkZeroOnes(String s) {
    int longestZero = 0;
    int longestOne = 0;
    int currentZero = 0;
    int currentOne = 0;

    for (char c : s.toCharArray()) {
        if (c == '0') {
            currentZero++;
            longestZero = Math.max(longestZero, currentZero);
            currentOne = 0;
        } else {
            currentOne++;
            longestOne = Math.max(longestOne, currentOne);
            currentZero = 0;
        }
    }
    return longestOne > longestZero;
}
```


